def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        modifier = 1.0
        if ratio > 2:
            for p in range(1, 7):
                penalty += ((-1)**p) * (ratio ** (2*p)) / (p ** 2 + 1)
            if capacity > item * 3:
                modifier = np.log2(capacity / item + 1)
            score = (ratio ** 5) + penalty * modifier
            if capacity % 2 == 0:
                score /= (capacity / item + 1)
        elif 1.5 < ratio <= 2:
            score = (ratio ** 4) * 1.5
            for q in range(1, 6):
                score += ((-1) ** q) * (ratio ** (q+1)) / (q + 0.3)
            if capacity < item * 1.8:
                score *= 1.2
        elif 1 < ratio <= 1.5:
            for r in range(1, 5):
                penalty += (ratio ** r) / (r * 2 + 0.5)
            score = (ratio ** 3) * 2 - penalty
            if abs(capacity - item) < 0.1*item:
                score += 3
        else:
            for j in range(1, 10):
                sign = -1 if j % 2 == 0 else 1
                inner_sum = 0
                for k in range(1, j+1):
                    inner_sum += (ratio ** k) / (k + 0.1*j)
                score += sign * inner_sum / (j + 0.3)
            if ratio < 0.1:
                multiplier = 25
                for m in range(1, 6):
                    score += (ratio ** m) / (m * 1.2)
            elif ratio < 0.3:
                multiplier = 18
                for m in range(2, 7):
                    score -= (ratio ** m) / (m + 0.7)
            elif ratio < 0.6:
                multiplier = 10
                for m in range(1, 6):
                    if m % 3 == 0:
                        score += (ratio ** m) / (m + 0.3)
                    else:
                        score -= (ratio ** m) / (m + 1)
            else:
                multiplier = 5
                for m in range(4, 9):
                    score += ((-1) ** (m+1)) * (ratio ** m) / (m + 0.9)
                if ratio > 0.85:
                    extra = 0
                    for n in range(1, 6):
                        extra += np.sqrt(ratio ** n) / (n + 0.4)
                    score += extra
            score = abs(score) * multiplier
            priorities[i] = score
            if capacity == item:
                priorities[i] += 7
            if priorities[i] < 0:
                priorities[i] = 0
            continue
        if score < 0:
            score = 0
        priorities[i] = score
        if capacity == item:
            priorities[i] += 7
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
